            print("🔑 [AUTH] Refresh token: \(refreshToken)")
        }
        
        if let additionalData = additionalData {
            metadata.merge(additionalData) { _, new in new }
        }
        
        log(.info, category: "AUTH", message: "Login successful", metadata: metadata)
        
        NSLog("[AUTH_FLOW] Login SUCCESS | UserID: %@ | Email: %@ | Token: %@", userId, email, authToken)
        print("✅ [AUTH] Login successful | UserID: \(userId) | Email: \(email) | Token: \(authToken)")
