        ]
        
        if let responseBody = responseBody {
            metadata["responseBody"] = responseBody
        }
        
        log(.error, category: "AUTH", message: "Login failed", metadata: metadata)
        
        NSLog("[AUTH_FLOW] Login FAILED | Email: %@ | Error: %@ | Response: %@", email, error.localizedDescription, responseBody ?? "nil")
        print("❌ [AUTH] Login failed | Email: \(email) | Error: \(error.localizedDescription) | Response: \(responseBody ?? "nil")")
    }
    
    func trackLogout(userId: String?, reason: String) {
        log(.info, category: "AUTH", message: "User logout", metadata: [
            "userId": userId ?? currentUserId ?? "unknown",
            "email": currentUserEmail ?? "unknown",
            "reason": reason,
            "lastToken": currentAuthToken ?? "none",
            "sessionId": sessionId
        ])
        
        NSLog("[AUTH_FLOW] Logout | UserID: %@ | Email: %@ | Reason: %@ | Token was: %@",
              userId ?? currentUserId ?? "unknown",
              currentUserEmail ?? "unknown",
              reason,
              currentAuthToken ?? "none")
        
        print("🚪 [AUTH] Logout | UserID: \(userId ?? currentUserId ?? "unknown") | Email: \(currentUserEmail ?? "unknown") | Reason: \(reason)")
        
