        ])
        
        NSLog("[AUTH_FLOW] Token refresh | Old: %@ | New: %@ | UserID: %@", oldToken, newToken, userId ?? currentUserId ?? "unknown")
        print("🔄 [AUTH] Token refresh | Old: \(oldToken) | New: \(newToken)")
