    // MARK: - API Call Tracking
    
    func trackAPIRequest(endpoint: String, method: String, headers: [String: String]?, body: Any?, requestId: String = UUID().uuidString) -> String {
        var metadata: [String: Any] = [
            "endpoint": endpoint,
            "method": method,
            "requestId": requestId,
            "userId": currentUserId ?? "anonymous",
            "sessionId": sessionId
        ]
        
        if let headers = headers {
            metadata["headers"] = headers
            // Log auth headers specifically for debugging
            if let authHeader = headers["Authorization"] {
                metadata["authorizationHeader"] = authHeader
                NSLog("[API_DEBUG] Authorization header: %@", authHeader)
                print("🔑 [API] Auth header: \(authHeader)")
            }
            if let apiKey = headers["X-API-Key"] {
                metadata["apiKey"] = apiKey
            }
        }
        
        if let body = body {
            if let bodyData = body as? Data, let bodyString = String(data: bodyData, encoding: .utf8) {
                metadata["requestBody"] = bodyString
                NSLog("[API_REQUEST] Body: %@", bodyString)
                print("📤 [API] Request body: \(bodyString)")
            } else if let bodyDict = body as? [String: Any] {
                metadata["requestBody"] = bodyDict
                if let jsonData = try? JSONSerialization.data(withJSONObject: bodyDict, options: .prettyPrinted),
                   let jsonString = String(data: jsonData, encoding: .utf8) {
                    NSLog("[API_REQUEST] Body JSON: %@", jsonString)
                    print("📤 [API] Request body: \(jsonString)")
                }
            } else {
                metadata["requestBody"] = "\(body)"
            }
        }
        
        log(.info, category: "API", message: "Request: \(method) \(endpoint)", metadata: metadata)
        
        NSLog("[API_REQUEST] %@ %@ | RequestID: %@ | UserID: %@ | Headers: %@",
              method, endpoint, requestId, currentUserId ?? "anonymous", "\(headers ?? [:])")
        
        print("🌐 [API] \(method) \(endpoint) | RequestID: \(requestId) | User: \(currentUserId ?? "anonymous")")
        
        return requestId
    }
    
    func trackAPIResponse(requestId: String, endpoint: String, statusCode: Int, headers: [String: String]?, responseBody: Any?, duration: TimeInterval) {
        var metadata: [String: Any] = [
            "requestId": requestId,
            "endpoint": endpoint,
            "statusCode": statusCode,
            "duration": "\(String(format: "%.3f", duration))s",
            "userId": currentUserId ?? "anonymous",
            "sessionId": sessionId
        ]
        
        if let headers = headers {
            metadata["responseHeaders"] = headers
        }
        
        if let responseBody = responseBody {
            if let bodyData = responseBody as? Data, let bodyString = String(data: bodyData, encoding: .utf8) {
                metadata["responseBody"] = bodyString
                NSLog("[API_RESPONSE] Body: %@", bodyString)
                print("📥 [API] Response body: \(bodyString)")
                
                // Parse and log specific fields for debugging
                if let json = try? JSONSerialization.jsonObject(with: bodyData) as? [String: Any] {
                    if let token = json["token"] as? String ?? json["access_token"] as? String {
                        NSLog("[API_RESPONSE] Token in response: %@", token)
                        print("🔑 [API] Token received: \(token)")
                    }
                    if let userId = json["user_id"] as? String ?? json["id"] as? String {
                        NSLog("[API_RESPONSE] UserID in response: %@", userId)
                    }
                    if let email = json["email"] as? String {
                        NSLog("[API_RESPONSE] Email in response: %@", email)
                    }
                    if let userData = json["user"] as? [String: Any] {
                        NSLog("[API_RESPONSE] User data: %@", "\(userData)")
                        print("👤 [API] User data in response: \(userData)")
                    }
                }
            } else if let bodyDict = responseBody as? [String: Any] {
                metadata["responseBody"] = bodyDict
                if let jsonData = try? JSONSerialization.data(withJSONObject: bodyDict, options: .prettyPrinted),
                   let jsonString = String(data: jsonData, encoding: .utf8) {
                    NSLog("[API_RESPONSE] Body JSON: %@", jsonString)
                    print("📥 [API] Response: \(jsonString)")
                }
            } else {
                metadata["responseBody"] = "\(responseBody)"
            }
        }
        
        let level: LogLevel = statusCode >= 400 ? .error : .info
        log(level, category: "API", message: "Response: \(statusCode) \(endpoint)", metadata: metadata)
        
        NSLog("[API_RESPONSE] %d %@ | RequestID: %@ | Duration: %.3fs | UserID: %@",
              statusCode, endpoint, requestId, duration, currentUserId ?? "anonymous")
        
        let emoji = statusCode >= 400 ? "❌" : "✅"
        print("\(emoji) [API] Response \(statusCode) \(endpoint) | Duration: \(String(format: "%.3f", duration))s | RequestID: \(requestId)")
    }
    
    func trackAPIError(requestId: String, endpoint: String, error: Error, requestBody: Any? = nil) {
        var metadata: [String: Any] = [
            "requestId": requestId,
            "endpoint": endpoint,
            "errorDescription": error.localizedDescription,
            "errorType": String(describing: type(of: error)),
            "errorDebug": "\(error)",
            "userId": currentUserId ?? "anonymous",
            "authToken": currentAuthToken ?? "none",
            "sessionId": sessionId
        ]
        
        if let nsError = error as NSError? {
            metadata["errorDomain"] = nsError.domain
            metadata["errorCode"] = nsError.code
            metadata["errorUserInfo"] = "\(nsError.userInfo)"
        }
        
        if let requestBody = requestBody {
            metadata["originalRequestBody"] = "\(requestBody)"
        }
        
        log(.error, category: "API", message: "Request error: \(endpoint)", metadata: metadata)
        
        NSLog("[API_ERROR] %@ | RequestID: %@ | Error: %@ | UserID: %@ | Token: %@",
              endpoint, requestId, error.localizedDescription, currentUserId ?? "anonymous", currentAuthToken ?? "none")
        
        print("🔥 [API] Error \(endpoint) | \(error.localizedDescription) | RequestID: \(requestId)")
    }
    
