    // MARK: - Error Tracking
    
    func trackError(_ error: Error, context: String, additionalInfo: [String: Any]? = nil, file: String = #file, function: String = #function, line: Int = #line) {
        var metadata: [String: Any] = [
            "context": context,
            "errorDescription": error.localizedDescription,
            "errorType": String(describing: type(of: error)),
            "errorDebug": "\(error)",
            "userId": currentUserId ?? "anonymous",
            "email": currentUserEmail ?? "unknown",
            "authToken": currentAuthToken ?? "none",
            "sessionId": sessionId
        ]
        
        if let nsError = error as NSError? {
            metadata["errorDomain"] = nsError.domain
            metadata["errorCode"] = nsError.code
            metadata["errorUserInfo"] = "\(nsError.userInfo)"
        }
        
        if let info = additionalInfo { metadata.merge(info) { _, new in new } }
        
        log(.error, category: "ERROR", message: "Error in \(context): \(error.localizedDescription)", metadata: metadata, file: file, function: function, line: line)
        
        NSLog("[ERROR] Context: %@ | Error: %@ | UserID: %@ | Email: %@ | Token: %@ | File: %@:%d",
              context, error.localizedDescription, currentUserId ?? "anonymous", currentUserEmail ?? "unknown",
              currentAuthToken ?? "none", (file as NSString).lastPathComponent, line)
        
        print("🔥 [ERROR] \(context) | \(error.localizedDescription) | User: \(currentUserId ?? "anonymous") | \((file as NSString).lastPathComponent):\(line)")
    }
    
    func trackCriticalError(_ error: Error, context: String, userState: [String: Any]? = nil) {
        var metadata: [String: Any] = [
            "context": context,
            "errorDescription": error.localizedDescription,
            "errorType": String(describing: type(of: error)),
            "userId": currentUserId ?? "anonymous",
            "email": currentUserEmail ?? "unknown",
            "authToken": currentAuthToken ?? "none",
            "sessionId": sessionId,
            "recentEvents": eventLog.suffix(20).map { "\($0.timestamp): \($0.event)" }
        ]
        
        if let state = userState { metadata["userState"] = state }
        
        log(.critical, category: "CRITICAL", message: "Critical error: \(context)", metadata: metadata)
        
        NSLog("[CRITICAL_ERROR] %@ | Error: %@ | UserID: %@ | Email: %@ | Token: %@ | Session: %@",
              context, "\(error)", currentUserId ?? "anonymous", currentUserEmail ?? "unknown",
              currentAuthToken ?? "none", sessionId)
        
        print("🚨 [CRITICAL] \(context) | \(error) | Full user state: UserID=\(currentUserId ?? "none"), Email=\(currentUserEmail ?? "none"), Token=\(currentAuthToken ?? "none")")
        
        // Dump recent events for crash context
        print("🚨 [CRITICAL] Recent events leading to error:")
        for event in eventLog.suffix(20) {
            print("  → \(event.event)")
        }
    }
    
    func trackNetworkError(url: String, statusCode: Int?, error: Error?, responseData: Data?) {
        var metadata: [String: Any] = [
            "url": url,
            "userId": currentUserId ?? "anonymous",
            "email": currentUserEmail ?? "unknown",
            "authToken": currentAuthToken ?? "none",
            "sessionId": sessionId
        ]
        
        if let statusCode = statusCode { metadata["statusCode"] = statusCode }
        if let error = error { metadata["error"] = error.localizedDescription }
        if let data = responseData, let body = String(data: data, encoding: .utf8) {
            metadata["responseBody"] = body
        }
        
        log(.error, category: "NETWORK", message: "Network error: \(url)", metadata: metadata)
        
        let responseString = responseData.flatMap { String(data: $0, encoding: .utf8) } ?? "nil"
        NSLog("[NETWORK_ERROR] URL: %@ | Status: %@ | Error: %@ | Response: %@ | UserID: %@ | Token: %@",
              url, "\(statusCode ?? -1)", error?.localizedDescription ?? "none", responseString,
              currentUserId ?? "anonymous", currentAuthToken ?? "none")
        
        print("🌐❌ [NETWORK] \(url) | Status: \(statusCode ?? -1) | Response: \(responseString)")
    }
    
