    // MARK: - Device & Environment Info
    
    func logDeviceInfo() {
        let device = UIDevice.current
        let info: [String: Any] = [
            "deviceModel": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "deviceName": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? "unknown",
            "batteryLevel": device.batteryLevel,
            "sessionId": sessionId,
            "userId": currentUserId ?? "none",
            "email": currentUserEmail ?? "none"
        ]
        
        log(.info, category: "DEVICE", message: "Device info", metadata: info)
        
        NSLog("[DEVICE_INFO] Model: %@ | OS: %@ %@ | DeviceName: %@ | VendorID: %@ | UserID: %@",
              device.model, device.systemName, device.systemVersion, device.name,
              device.identifierForVendor?.uuidString ?? "unknown", currentUserId ?? "none")
        
        print("📱 [DEVICE] \(device.model) | \(device.systemName) \(device.systemVersion) | \(device.name)")
    }
    
    // MARK: - Crash Report Context
    
    func generateCrashReportContext() -> [String: Any] {
        let context: [String: Any] = [
            "sessionId": sessionId,
            "currentUserId": currentUserId ?? "none",
            "currentUserEmail": currentUserEmail ?? "none",
            "currentAuthToken": currentAuthToken ?? "none",
            "eventCount": eventLog.count,
            "recentEvents": eventLog.suffix(50).map { [
                "timestamp": dateFormatter.string(from: $0.timestamp),
                "event": $0.event
            ]},
            "timestamp": dateFormatter.string(from: Date())
        ]
        
        NSLog("[CRASH_CONTEXT] UserID: %@ | Email: %@ | Token: %@ | Session: %@ | Events: %d",
              currentUserId ?? "none", currentUserEmail ?? "none", currentAuthToken ?? "none",
              sessionId, eventLog.count)
        
        print("🚨 [CRASH CONTEXT] Full context generated:")
        print("  UserID: \(currentUserId ?? "none")")
        print("  Email: \(currentUserEmail ?? "none")")
        print("  Token: \(currentAuthToken ?? "none")")
        print("  Session: \(sessionId)")
        print("  Event count: \(eventLog.count)")
        
        return context
    }
    
    // MARK: - Log Retrieval
    
    func getRecentLogs(count: Int = 100) -> [(timestamp: Date, event: String)] {
        return Array(eventLog.suffix(count))
    }
    
    func exportLogs() -> String {
        return eventLog.map { "\(dateFormatter.string(from: $0.timestamp)): \($0.event)" }.joined(separator: "\n")
    }
    
    func clearLogs() {
        logQueue.async { [weak self] in
            self?.eventLog.removeAll()
            NSLog("[ANALYTICS] Logs cleared | SessionID: %@", self?.sessionId ?? "unknown")
        }
    }
}

// MARK: - Network Interceptor for Automatic API Logging

class AnalyticsURLProtocol: URLProtocol {
    
    private var startTime: Date?
    private var dataTask: URLSessionDataTask?
    private var receivedData = Data()
    
    static let handledKey = "AnalyticsURLProtocolHandled"
    
    override class func canInit(with request: URLRequest) -> Bool {
        if URLProtocol.property(forKey: handledKey, in: request) != nil {
            return false
        }
        return true
    }
    
    override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        return request
    }
    
    override func startLoading() {
        startTime = Date()
        
        let mutableRequest = (request as NSURLRequest).mutableCopy() as! NSMutableURLRequest
        URLProtocol.setProperty(true, forKey: AnalyticsURLProtocol.handledKey, in: mutableRequest)
        
        // Log outgoing request with full details
        let headers = request.allHTTPHeaderFields
        let body = request.httpBody
        
        let requestId = AnalyticsDebugManager.shared.trackAPIRequest(
            endpoint: request.url?.absoluteString ?? "unknown",
            method: request.httpMethod ?? "GET",
            headers: headers,
            body: body
        )
        
        // Store requestId for response tracking
        URLProtocol.setProperty(requestId, forKey: "requestId", in: mutableRequest)
        
        let session = URLSession(configuration: .default, delegate: self, delegateQueue: nil)
        dataTask = session.dataTask(with: mutableRequest as URLRequest)
        dataTask?.resume()
    }
    
    override func stopLoading() {
        dataTask?.cancel()
    }
}

extension AnalyticsURLProtocol: URLSessionDataDelegate {
    
    func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive data: Data) {
        receivedData.append(data)
        client?.urlProtocol(self, didLoad: data)
    }
    
    func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive response: URLResponse, completionHandler: @escaping (URLSession.ResponseDisposition) -> Void) {
        client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
        completionHandler(.allow)
    }
    
    func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        let duration = startTime.map { Date().timeIntervalSince($0) } ?? 0
        let requestId = URLProtocol.property(forKey: "requestId", in: task.originalRequest! as URLRequest) as? String ?? "unknown"
        
        if let error = error {
            AnalyticsDebugManager.shared.trackAPIError(
                requestId: requestId,
                endpoint: task.originalRequest?.url?.absoluteString ?? "unknown",
                error: error,
                requestBody: task.originalRequest?.httpBody
            )
            client?.urlProtocol(self, didFailWithError: error)
        } else {
            let httpResponse = task.response as? HTTPURLResponse
            let responseHeaders = httpResponse?.allHeaderFields as? [String: String]
            
            AnalyticsDebugManager.shared.trackAPIResponse(
                requestId: requestId,
                endpoint: task.originalRequest?.url?.absoluteString ?? "unknown",
                statusCode: httpResponse?.statusCode ?? -1,
                headers: responseHeaders,
                responseBody: receivedData,
                duration: duration
            )
            client?.urlProtocolDidFinishLoading(self)
        }
    }
}

