// MARK: - Property Wrapper for Tracked User Defaults

@propertyWrapper
struct TrackedUserDefault<T> {
    let key: String
    let defaultValue: T
    let fieldName: String
    
    var wrappedValue: T {
        get {
            return UserDefaults.standard.object(forKey: key) as? T ?? defaultValue
        }
        set {
            let oldValue = UserDefaults.standard.object(forKey: key) as? T ?? defaultValue
            UserDefaults.standard.set(newValue, forKey: key)
            AnalyticsDebugManager.shared.trackUserDataChange(
                field: fieldName,
                oldValue: oldValue,
                newValue: newValue
            )
        }
    }
}

