// MARK: - Crash Handler Setup

class CrashReportingIntegration {
    
    static func setup() {
        NSSetUncaughtExceptionHandler { exception in
            let context = AnalyticsDebugManager.shared.generateCrashReportContext()
            
            NSLog("[CRASH] Uncaught exception: %@ | Reason: %@ | UserInfo: %@",
                  exception.name.rawValue,
                  exception.reason ?? "unknown",
                  "\(exception.userInfo ?? [:])")
            
            NSLog("[CRASH] Call stack: %@", exception.callStackSymbols.joined(separator: "\n"))
            NSLog("[CRASH] User context: %@", "\(context)")
            
            print("💥 [CRASH] \(exception.name.rawValue): \(exception.reason ?? "unknown")")
            print("💥 [CRASH] Stack trace:")
            exception.callStackSymbols.forEach { print("  \($0)") }
            print("💥 [CRASH] User context: \(context)")
        }
        
        // Signal handler for additional crash types
        signal(SIGABRT) { signal in
            let context = AnalyticsDebugManager.shared.generateCrashReportContext()
            NSLog("[CRASH] Signal %d received | Context: %@", signal, "\(context)")
        }
        signal(SIGSEGV) { signal in
            let context = AnalyticsDebugManager.shared.generateCrashReportContext()
            NSLog("[CRASH] Signal %d received | Context: %@", signal, "\(context)")
        }
        
        AnalyticsDebugManager.shared.log(.info, category: "SETUP", message: "Crash reporting initialized")
    }
}